# DK HBV.  Holstebro - Vejle
with detail = 2 {
    let hv = path("d2.dk.hbv");

    with railway = :first :pax {
        with link = "line.dk.HBV" {
            track(hv[:hol.yv, :hol.yv + 9.21km]);
            line_label(:left:sw, hv[:hol.yv + 9.2km] << 0.5mt, "HBV");
            track(hv[:hol.yv + 9.19km, :her.yh - 7.99km]);
            line_label(:left:s, hv[:her.yh - 8km] << 0.5mt, "HBV");
            track(hv[:her.yh - 8.01km, :her.yh]);
        }

        with link = "point.dk.Herning", railway = :station {
            track(hv[:her.yh, :her.ys]);
            statdot(hv[:her]);
            slabel(:left, hv[:her.yh] + (-1km, 0dt) + (-2dt, 1.5dt),
                "Herning"
            );
        }

        with link = "line.dk.HBV" {
            track(hv[:her.ys, :her.ys + 11.01km]);
            line_label(:right:e, hv[:her.ys + 11km] >> 0.5mt,
                (0dt, 0.2dt), "HBV"
            );
            track(hv[:her.ys + 10.99km, :brd.yf]);
        }

        with link = "point.dk.Brande", railway = :station {
            track(hv[:brd.yf, :brd.yb]);
            statdot(hv[:brd]);
            slabel(:left, hv[:brd] + (-1.5dt, 1.5dt), "Brande");
        }

        with link = "line.dk.HBV" {
            track(hv[:brd.yb, :brd.yb + 6.01km]);
            line_label(:left:s, hv[:brd.yb + 6km] << 0.5mt, "HBV");
            track(hv[:brd.yb + 5.99km, :thy.yh]);
        }

        with link = "point.dk.Thyregod", railway = :station {
            track(hv[:thy.yh, :thy]);
            statdot(hv[:thy]);
            slabel(:left, hv[:thy] + (-1.5dt, 0.6dt), "Thyregod");
        }

        with link = "line.dk.HBV" {
            track(hv[:thy, :thy + 9.01km]);
            line_label(:left:w, hv[:thy + 9km] << 0.5mt, "HBV");
            track(hv[:thy + 8.99km, :ven - 4.91km]);
            line_label(:left:sw, hv[:ven - 4.9km] << 0.5mt, "HBV");
            track(hv[:ven - 4.89km, :ven]);
        }

        with link = "point.dk.Vejle-Nord", railway = :station {
            statdot(:removed, hv[:ven]);
            slabel(:right :removed, hv[:ven] + (1.3dt, -1dt), "V. Nord");
        }

        with link = "line.dk.HBV" {
            track(
                    hv[:ven - 0.1dl, :ven]
                ..  hv[:vej.yh, :vej.yh + 0.1dl] >> 0.5md << 0.5mt
            );
        }
    }
}


